import { describe, it, expect } from "vitest";
import { quote, claim } from "./claim-office.js";

describe("MHPCO Claim Office — quote", () => {
  // Simplest case
  it.todo("empty item list → premium 5 G (only processing fee)");

  // Base premiums per item type (newcomer, no modifiers beyond first insurance & fee)
  it.todo("single plain sword for newcomer (no prior contracts) → base 100 + 10 first + 5 fee = 115 G");
  it.todo("single plain amulet for newcomer → base 60 + 6 first + 5 fee = 71 G");
  it.todo("single plain staff for newcomer → base 80 + 8 first + 5 fee = 93 G");
  it.todo("single plain potion for newcomer → base 40 + 4 first + 5 fee = 49 G");

  // Components — base premiums (newcomer; verifying base before block rule)
  it.todo("2 runes → base 50 G (no block; +5 first +5 fee = 60 G)");
  it.todo("3 runes → base 60 G via block (+6 first +5 fee = 71 G)");
  it.todo("4 runes → base 100 G (no block; block requires exactly 3) → +10 first +5 fee = 115 G");
  it.todo("7 runes → base 175 G");

  // "Alike" components clarification
  it.todo("2 runes + 1 moonstone → base 75 G (no block — different types)");
  it.todo("3 runes + 3 moonstones → base 120 G (two separate blocks)");

  // Item-specific modifiers
  it.todo("cursed sword for newcomer → 100 + 50 curse + 10 first + 5 fee = 165 G");
  it.todo("sword with enchantment exactly 5 (newcomer) → 100 + 30 high-ench + 10 first + 5 fee = 145 G");
  it.todo("sword with enchantment 4 (newcomer) → no high-ench surcharge → 115 G");
  it.todo("cursed sword with enchantment 5 (newcomer) → both surcharges apply");

  // Modifier scope on multi-item policies (clarifying question ❓)
  it.todo("policy: cursed sword + plain amulet → 210 G before further modifiers and fee (newcomer additions extra)");

  // Loyalty discount threshold
  it.todo("customer with exactly 2 years → loyalty discount applies (20% of policy base)");
  it.todo("customer with 1 year → no loyalty discount");

  // Follow-up contract discount (each contract after the first → 15% off policy base)
  it.todo("second contract for same customer in same scenario → 15% follow-up discount applies");

  // First insurance per item, regardless of customer history (❓ clarification)
  it.todo("long-standing customer's second contract: cursed sword ench 7 → premium 160 G (matches spec integration example)");

  // Rounding in MHPCO's favor
  it.todo("premium calculation yielding 197.5 → final premium 198 (rounded up)");

  // Errors
  it.todo("unknown item type in quote → throws error");
});

describe("MHPCO Claim Office — claim", () => {
  // Standard reimbursement (no special clauses)
  it.todo("regular steel sword ench 3, damage 500 → payout 400 (500 − 100 deductible)");
  it.todo("rune (no enchantment / material), damage 200 → payout 100 (200 − 100 deductible)");

  // Enchantment ≥8 clause
  it.todo("steel sword ench 9, damage 1000 → payout 400 (50% then deductible)");

  // Dragon material clause
  it.todo("dragon-material sword ench 5, damage 800 → payout 700 (full, then deductible)");

  // Both clauses — 50% wins, then deductible
  it.todo("dragon-material sword ench 9, damage 1000 → payout 400");
  it.todo("dragon-material sword ench exactly 8, damage 1000 → payout 400 (high-ench applies, then deductible)");

  // Deductible per damage event
  it.todo("dragon attack damaging sword 500 + amulet 300 → payout 600 (deductible per item)");

  // Multiple items of same type
  it.todo("policy with two swords; damage to both → each treated as separate damage with own deductible");
  it.todo("damages array has more entries of a type than the policy covers → throws error");

  // Cap exhaustion
  it.todo("policy: sword + amulet → insurance sum 1600, cap 3200");
  it.todo("policy: cursed sword → cap 2000 (based on unmodified insurance value)");
  it.todo("policy: sword + 3 runes (block) → insurance sum 1750 (block doesn't affect sum)");
  it.todo("sword (cap 2000), first claim 1500 → payout 1400, remaining 600; second claim 1500 → payout 600, remaining 0");

  // Rounding for payouts
  it.todo("payout calculation yielding 350.5 → final payout 350 (rounded down)");

  // Errors
  it.todo("claim references damage for an item not in the policy → throws error");
  it.todo("claim contains damage with negative amount → throws error");
});

