export interface Customer {
  yearsWithMHPCO: number;
}

export interface Item {
  type: string;
}

export interface Damage {
  itemType: string;
  amount: number;
}

export interface Incident {
  cause: string;
  damages: Damage[];
}

export interface Policy {
  items: Item[];
  insuranceSum: number;
  cap: number;
  remainingCap: number;
}

const PROCESSING_FEE = 5;
const FIRST_INSURANCE_RATE = 0.1;

const BASE_PREMIUM: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
};

const premiumForItem = (item: Item): number => {
  const base = BASE_PREMIUM[item.type];
  const firstInsuranceSurcharge = base * FIRST_INSURANCE_RATE;
  return base + firstInsuranceSurcharge;
};

export const quote = (
  _customer: Customer,
  items: Item[],
  _priorContracts: number,
): number => {
  const itemsTotal = items.reduce((sum, item) => sum + premiumForItem(item), 0);
  return itemsTotal + PROCESSING_FEE;
};

export const claim = (
  _policy: Policy,
  _incident: Incident,
): { payout: number; remainingCap: number } => {
  return undefined as unknown as { payout: number; remainingCap: number };
};

