const COMPONENT_TYPES = new Set(["rune"]);
const BLOCK_BASE = 60;

const baseForGroup = (type: string, count: number): number => {
  if (COMPONENT_TYPES.has(type) && count === 3) return BLOCK_BASE;
  return BASE_PREMIUM[type] * count;
};

const groupByType = (items: Item[]): Map<string, number> => {
  const counts = new Map<string, number>();
  for (const item of items) {
    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
  }
  return counts;
};

export const quote = (
  _customer: Customer,
  items: Item[],
  _priorContracts: number,
): number => {
  const groups = groupByType(items);
  let itemsTotal = 0;
  for (const [type, count] of groups) {
    const base = baseForGroup(type, count);
    itemsTotal += base + base * FIRST_INSURANCE_RATE;
  }
  return itemsTotal + PROCESSING_FEE;
};

