export interface Customer {
  yearsWithMHPCO: number;
}

export interface Item {
  type: string;
}

export interface Damage {
  itemType: string;
  amount: number;
}

export interface Incident {
  cause: string;
  damages: Damage[];
}

export interface Policy {
  items: Item[];
  insuranceSum: number;
  cap: number;
  remainingCap: number;
}

const PROCESSING_FEE = 5;
const FIRST_INSURANCE_RATE = 0.1;

const BASE_PREMIUM: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
  moonstone: 25,
};

const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
const BLOCK_BASE = 60;

const baseForGroup = (type: string, count: number): number => {
  if (COMPONENT_TYPES.has(type) && count === 3) return BLOCK_BASE;
  return BASE_PREMIUM[type] * count;
};

const countByType = (items: Item[]): Map<string, number> => {
  const counts = new Map<string, number>();
  for (const item of items) {
    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
  }
  return counts;
};

const withFirstInsurance = (base: number): number =>
  base + base * FIRST_INSURANCE_RATE;

export const quote = (
  _customer: Customer,
  items: Item[],
  _priorContracts: number,
): number => {
  let itemsTotal = 0;
  for (const [type, count] of countByType(items)) {
    itemsTotal += withFirstInsurance(baseForGroup(type, count));
  }
  return Math.ceil(itemsTotal + PROCESSING_FEE);
};

export const claim = (
  _policy: Policy,
  _incident: Incident,
): { payout: number; remainingCap: number } => {
  return undefined as unknown as { payout: number; remainingCap: number };
};

