  return total;
};

const LOYALTY_THRESHOLD_YEARS = 2;
const LOYALTY_DISCOUNT_RATE = 0.2;

export const quote = (
  customer: Customer,
  items: Item[],
  _priorContracts: number,
): number => {
  const groupBase = groupBaseTotal(items);
  const firstInsurance = groupBase * FIRST_INSURANCE_RATE;
  const surcharges = itemSurchargeTotal(items);
  const loyaltyDiscount =
    customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS ? groupBase * LOYALTY_DISCOUNT_RATE : 0;
  return Math.ceil(
    groupBase + firstInsurance + surcharges - loyaltyDiscount + PROCESSING_FEE,
  );
};

export const claim = (
  _policy: Policy,
  _incident: Incident,
): { payout: number; remainingCap: number } => {
  return undefined as unknown as { payout: number; remainingCap: number };
};

