  it("policy: cursed sword + plain amulet → 231 G (210 + 16 first + 5 fee)", () => {
    expect(
      quote({ yearsWithMHPCO: 0 }, [{ type: "sword", cursed: true }, { type: "amulet" }], 0),
    ).toBe(231);
  });

