  sum(items.map((item) => surchargesFor(item)));

const surchargesFor = (item: Item): number => {
  const base = BASE_PREMIUM[item.type];
  let total = 0;
  if (item.cursed) total += base * 0.5;
  if ((item.enchantment ?? 0) >= 5) total += base * 0.3;
  return total;
};

