export const claim = (
  policy: Policy,
  incident: Incident,
): { payout: number; remainingCap: number } => {
  const payout = sum(incident.damages.map((damage) => payoutForDamage(damage, policy)));
  return { payout, remainingCap: policy.remainingCap - payout };
};

