109	const LOYALTY_DISCOUNT_RATE = 0.2;
110	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
111	
112	export const quote = (
113	  customer: Customer,
114	  items: Item[],
115	  priorContracts: number,
116	): number => {
117	  assertKnownItemTypes(items);
118	  const groupBase = groupBaseTotal(items);
119	  const firstInsurance = groupBase * FIRST_INSURANCE_RATE;
120	  const surcharges = itemSurchargeTotal(items);
121	  const loyaltyDiscount =
122	    customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS ? groupBase * LOYALTY_DISCOUNT_RATE : 0;
123	  const followUpDiscount = priorContracts > 0 ? groupBase * FOLLOW_UP_DISCOUNT_RATE : 0;
124	  return Math.ceil(
125	    groupBase + firstInsurance + surcharges - loyaltyDiscount - followUpDiscount + PROCESSING_FEE,
126	  );
127	};
128	
129	const DEDUCTIBLE = 100;
130	const HIGH_ENCHANTMENT_CLAIM_THRESHOLD = 8;
131	const HIGH_ENCHANTMENT_REIMBURSEMENT_RATE = 0.5;
132	
133	const isHighlyEnchanted = (item: Item | undefined): boolean =>
134	  (item?.enchantment ?? 0) >= HIGH_ENCHANTMENT_CLAIM_THRESHOLD;
135	
136	const reimbursableAmount = (damage: Damage, item: Item | undefined): number =>
137	  isHighlyEnchanted(item)
138	    ? damage.amount * HIGH_ENCHANTMENT_REIMBURSEMENT_RATE
139	    : damage.amount;
140	
141	const findInsuredItem = (policy: Policy, itemType: string): Item | undefined =>
142	  policy.items.find((item) => item.type === itemType);
143	
144	const payoutForDamage = (damage: Damage, policy: Policy): number => {
145	  const item = findInsuredItem(policy, damage.itemType);
146	  return reimbursableAmount(damage, item) - DEDUCTIBLE;
147	};
148	
149	const assertDamagesNonNegative = (damages: Damage[]): void => {
150	  const negative = damages.find((damage) => damage.amount < 0);
151	  if (negative) {
152	    throw new Error(`Damage amount must be non-negative: ${negative.amount}`);
153	  }
154	};
155	
156	const assertDamagesCovered = (policy: Policy, damages: Damage[]): void => {
157	  const itemCounts = countByType(policy.items);
158	  const damageCounts = countBy(damages, (damage) => damage.itemType);
159	  for (const [type, count] of damageCounts) {
160	    if (count > (itemCounts.get(type) ?? 0)) {
161	      throw new Error(`Damage count for ${type} exceeds policy coverage`);
162	    }
163	  }
164	};
165	
166	const totalPayoutBeforeCap = (policy: Policy, damages: Damage[]): number =>
167	  sum(damages.map((damage) => payoutForDamage(damage, policy)));
168	
169	const cappedPayout = (policy: Policy, damages: Damage[]): number =>
170	  Math.floor(Math.min(totalPayoutBeforeCap(policy, damages), policy.remainingCap));
171	
172	export const claim = (
173	  policy: Policy,
174	  incident: Incident,
175	): { payout: number; remainingCap: number } => {
176	  assertDamagesNonNegative(incident.damages);
177	  assertDamagesCovered(policy, incident.damages);
178	  const payout = cappedPayout(policy, incident.damages);
179	  return { payout, remainingCap: policy.remainingCap - payout };
180	};

